      } catch (error) {
        console.error('Error loading notes data:', error);
        this.error = 'Failed to load notes';
        if (error.message.includes('token') || error.response?.status === 401) {
          localStorage.removeItem('token');
          this.$router.push('/login');
        }
      } finally {
        this.loading = false;
      }
    },
    filterNotes() {
      let filtered = [...this.notes];

      // Filter by search query
      if (this.searchQuery) {
        const query = this.searchQuery.toLowerCase();
        filtered = filtered.filter(note => note.title.toLowerCase().includes(query) || note.content.toLowerCase().includes(query));
      }

      // Filter by category
      if (this.selectedCategory) {
        filtered = filtered.filter(note => note.category === this.selectedCategory);
      }
      this.filteredNotes = filtered;
      this.sortNotes();
    },
    sortNotes() {
      this.filteredNotes.sort((a, b) => {
        switch (this.sortBy) {
          case 'title':
            return a.title.localeCompare(b.title);
          case 'category':
            return a.category.localeCompare(b.category);
          case 'date':
          default:
            return new Date(b.updatedAt) - new Date(a.updatedAt);
        }
      });
    },
    openNote(note) {
      this.noteForm = {
        id: note.id,
        title: note.title,
        content: note.content,
        category: note.category
      };
      this.showEditModal = true;
    },
    closeModal() {
      this.showCreateModal = false;
      this.showEditModal = false;
      this.noteForm = {
        id: null,
        title: '',
        content: '',
        category: ''
      };
    },
    saveNote() {
      if (!this.noteForm.title.trim() || !this.noteForm.content.trim()) {
        alert('Please fill in both title and content');
        return;
      }
      if (this.showEditModal) {
        // Update existing note
        const noteIndex = this.notes.findIndex(n => n.id === this.noteForm.id);
        if (noteIndex !== -1) {
          this.notes[noteIndex] = {
            ...this.notes[noteIndex],
            title: this.noteForm.title,
            content: this.noteForm.content,
            category: this.noteForm.category,
            updatedAt: new Date()
          };
        }
      } else {
        // Create new note
        const newNote = {
          id: Date.now(),
          title: this.noteForm.title,
          content: this.noteForm.content,
          category: this.noteForm.category || 'General',
          isFavorite: false,
          createdAt: new Date(),
          updatedAt: new Date()
        };
        this.notes.unshift(newNote);

        // Update category count
        const category = this.categories.find(c => c.name === newNote.category);
        if (category) {
          category.noteCount++;
        }
      }
      this.filterNotes();
      this.closeModal();
    },
    deleteNote(noteId) {
      if (confirm('Are you sure you want to delete this note?')) {
        const noteIndex = this.notes.findIndex(n => n.id === noteId);
        if (noteIndex !== -1) {
          const note = this.notes[noteIndex];
          this.notes.splice(noteIndex, 1);

          // Update category count
          const category = this.categories.find(c => c.name === note.category);
          if (category && category.noteCount > 0) {
            category.noteCount--;
          }
          this.filterNotes();
        }
      }
